mapper.select:
SELECT l.id, l.title, l.business_type AS businessType, l.method, l.request_url AS requestUrl,
       l.request_param AS requestParam, l.response_result AS responseResult,
       l.operator_id AS operatorId, u.real_name AS operatorName,
       l.oper_time AS operTime, l.oper_ip AS operIp
FROM sys_log l
LEFT JOIN sys_user u ON u.id = l.operator_id AND u.deleted = 0

    l.deleted = 0

        AND l.title LIKE CONCAT('%', #{query.title}, '%')


        AND l.business_type = #{query.businessType}


        AND l.operator_id = #{query.operatorId}


        AND l.oper_time >= #{query.beginTime}


        AND l.oper_time <= #{query.endTime}


ORDER BY l.oper_time DESC
